SELECT a.comp_name, a.com_code, a.type, ( SELECT COUNT(*) FROM ELIB_BOOK b WHERE b.use_yn != 'N' AND b.com_code = a.com_code AND INSTR(b.type, #{type}) > 0
AND b.approved_yn = #{approved_yn}
) AS cnt, use_yn FROM ELIB_COMPANY a WHERE 1=1 AND use_yn = 'Y'
AND INSTR(a.type, #{type}) > 0

mapper.update:
UPDATE ELIB_COMPANY SET
	com_code = #{com_code}
	,comp_name = #{comp_name}
	,type = #{type}
	,user_cnt = #{user_cnt}
	,license_sdate = TO_DATE(#{license_sdate}, 'YYYY-MM-DD')
	,license_edate = TO_DATE(#{license_edate}, 'YYYY-MM-DD')
	,copyright = #{copyright}


	,use_yn = 'N'


	,use_yn = 'Y'


	,mod_id = #{mod_id}
	,mod_date = SYSDATE
WHERE
	comp_idx = #{comp_idx}
